import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);
        String output = "Hello, " + sanitizedInput + "!";

        PrintWriter out = response.getWriter();
        out.println("<html><body>");
        out.println("<h1>" + output + "</h1>");
        out.println("</body></html>");
    }

    private String sanitizeInput(String input) {
        // Implement your sanitization logic here
        // Example: Using OWASP Java HTML Sanitizer library
        return org.owasp.html.PolicyFactory.sanitize(input);
    }
}

